export.skill:
{
  "id": "mesh",
  "description": "Mesh skill definition. The skill generates a reconstructed 3D mesh from the point cloud of a specified object.",
  "version": "1.0.0",
  "interface": "action",
  "default_interface_path": "src/mesh_skill_msgs/action",
  "datatype": "mesh_skill_msgs/action/Mesh",
  "parameters": {
    "in": [
      {
        "name": "scan_id",
        "type": "string",
        "description": "This parameter uniquely identifies the object to generate the mesh for."
      }
    ],
    "out": [
      {
        "name": "result",
        "type": "int64",
        "description": "This parameter represents the result and enables specifying various types of success and failure."
      }
    ]
  },
  "functional_domains": [
    "perception"
  ]
}
